<script>
import AdIndex from '@/components/Home/Ad_Top.vue'
import Slider from '@/components/Home/Slider.vue'

export default {
  name: 'Index',
  components: {
    AdIndex,
    Slider
  },
  data() {
    return {
      showNumber: 8,
      showNumberOther: 12,
      typeList: [],
      navLeftList: [],
      navRightList: [],
      gameList: [],
      gameList2: [],
      gameList3: [],
      gameListRecent: [],
      gameListNew: [],
      gameListOther: [],
      curType: '已汉化',
      curType2: '汉化中'
    }
  },
  created() {
    this.getData()
    this.getNavData()
  },
  computed: {
    filteredGameListNew() {
      return this.gameListNew.slice(0, this.showNumber)
    },
    filteredGameListRecent() {
      return this.gameListRecent.slice(0, this.showNumber)
    },
    filteredGameList() {
      return this.gameList.slice(0, this.showNumber)
    },
    filteredGameList2() {
      return this.gameList2.slice(0, this.showNumber)
    },
    filteredGameList3() {
      return this.gameList3.slice(0, this.showNumberOther)
    }
  },
  methods: {
    getData() {
      const timeStamp = new Date().getTime()
      this.$http.get('static/data/games.json' + '?' + timeStamp).then(game => {
        const activeGames = game.data.filter(g => g.status !== 0)
        this.gameList = activeGames.filter(g => g.type.includes(this.curType))
        this.gameList2 = activeGames.filter(g => g.type.includes(this.curType2) && !g.type.includes(this.curType))
        this.gameList3 = activeGames.filter(g => !g.type.includes(this.curType) && !g.type.includes(this.curType2))
        // 最近更新
        this.gameListRecent = activeGames
          .filter(g => g.update)
          .map(g => ({ ...g, _sortUpdate: Date.parse(new Date(g.update)) }))
          .sort((a, b) => a._sortUpdate - b._sortUpdate)
          .reverse()
          .map(({ _sortUpdate, ...g }) => g)
        // 最近发布
        this.gameListNew = activeGames
          .filter(g => g.date)
          .map(g => ({ ...g, _sortDate: Date.parse(new Date(g.date)) }))
          .sort((a, b) => a._sortDate - b._sortDate)
          .reverse()
          .map(({ _sortDate, ...g }) => g)
      })
    },
    getNavData() {
      const timeStamp = new Date().getTime()
      this.$http.get('static/data/home_nav_box.json' + '?' + timeStamp).then(game => {
        this.navLeftList = game.data[0].left.filter(item => item.status === 1)
        this.navRightList = game.data[1].right.filter(item => item.status === 1)
      })
    }
  }
}

</script>

