                      <a :href="'static/flash/'+game.path+'.html'" :title="game.title" target="_blank">
                        <div class="face-box games" :title="game.title">
                          <el-image class="img-responsive" :src="'static/images/game/'+game.path+'/jietu-1.png'" :alt="game.title">
                            <div slot="placeholder" class="img-placeholder small">
                              图片加载中<span class="dot">...</span>
                            </div>
                          </el-image>
                        </div>
                      </a>
                      <div>
                        <h5>
                          {{ game.title }}
                          <span v-if="game.version">v {{ game.version }}</span>
                          <span v-if="!game.version"> </span>
                        </h5>
                        <p>
                          <a
                              class=" hvr-wobble-top"
                              :href="'static/flash/'+game.path+'.html'"
                              :title="game.title"
                              target="_blank">
                            看介绍
                          </a>
                          <a
