              </section>
            </div>
          </div>
          <el-pagination
              background
              @size-change="handleSizeChange"
              @current-change="handleCurrentChange"
              :current-page="currentPage"
              :page-sizes="[12, 30, 50, 100]"
              :page-size="pagesize"
              layout="total, sizes, prev, pager, next, jumper"
              :total="total">
          </el-pagination>
        </div>
      </div>
    </div>
    <!--游戏分类 end-->
  </div>
</template>

<script>
export default {
  name: 'Demo',
  components: {},
  data() {
    return {
      total: 0,
      currentPage: 1,
      pagesize: 12,
      typeList: [],
      sortTypeList: [],
      gameList: [],
      curType: '全部游戏',
      activeClass: 0
    }
  },
  created() {
    this.getType()
    this.getData()
  },
  computed: {
    filteredTypeList() {
      const excludedIndices = [0, 1, 2, 13, 14, 15, 16, 17, 18, 19, 34, 36, 40, 50, 51, 52, 53, 54]
      return this.typeList.filter((t, index) => !excludedIndices.includes(index))
    },
    gameData() {
      return this.gameList.slice((this.currentPage - 1) * this.pagesize, this.currentPage * this.pagesize)
    }
  },
  methods: {
    getType() {
      const timeStamp = new Date().getTime()
      this.$http.get('static/data/type.json' + '?' + timeStamp).then(res => {
        const obj = res.data[0]
        this.typeList = Object.keys(obj).sort((a, b) => a - b).map(k => obj[k])
        this.curType = this.typeList[this.activeClass]
      })
    },
    getData() {
      const timeStamp = new Date().getTime()
      this.$http.get('static/data/games.json' + '?' + timeStamp).then(game => {
        const activeGames = game.data.filter(g => g.status === 1)

        if (this.curType === '全部游戏') {
          this.gameList = activeGames
        } else if (this.curType === '最近更新' && this.sortTypeList.length === 1) {
          this.gameList = activeGames
            .filter(g => g.update)
            .map(g => ({ ...g, _sortUpdate: Date.parse(new Date(g.update)) }))
            .sort((a, b) => b._sortUpdate - a._sortUpdate)
            .map(({ _sortUpdate, ...g }) => g)
        } else {
          this.gameList = activeGames.filter(g =>
            this.sortTypeList.every(sortType => g.type.includes(sortType))
          )
        }

        this.total = this.gameList.length

        if (this.gameList.length < 1) {
          this.$notify({
            title: '提示',
            message: '没找到你要查找的游戏，您可以减少筛选条件试试~',
            type: 'warning',
            duration: 1500
          })
        }
      })
    },
    getItem(indexOrType) {
      const index = typeof indexOrType === 'number' ? indexOrType : this.typeList.indexOf(indexOrType)
      this.activeClass = index
      this.gameList = []
      this.curType = this.typeList[index]

      if (index !== 0) {
        if (!this.sortTypeList.includes(this.curType)) {
          this.sortTypeList.push(this.curType)
        }
      }

      if (this.sortTypeList.length === 0) {
        this.curType = '全部游戏'
      }
      this.getData()
      this.currentPage = 1
    },
    delItem(text) {
      this.sortTypeList = this.sortTypeList.filter(item => item !== text)
      if (this.sortTypeList.length > 0) {
        this.curType = this.sortTypeList[this.sortTypeList.length - 1]
      } else {
        this.curType = '全部游戏'
      }
      this.gameList = []
      this.getData()
      this.currentPage = 1
    },
    clearSortItem() {
      if (this.sortTypeList.length !== 0) {
        this.sortTypeList = []
        this.gameList = []
        this.curType = '全部游戏'
        this.getData()
        this.currentPage = 1
      } else {
        this.$notify({
          title: '提示',
          message: '请选择一个筛选条件',
          type: 'warning',
          duration: 1500
        })
      }
    },
    handleSizeChange(size) {
      this.pagesize = size
    },
    handleCurrentChange(currentPage) {
      this.currentPage = currentPage
    }
  }
}

</script>

